// ── Impulsar planificación (tras Obtener días analizados) ───────────────────
// Postgres puede devolver analyzed_date = null (sin días previos).
// Este nodo SIEMPRE emite 1 item para que Planificar se ejecute.

const analyzedDates = [];

for (const item of $input.all()) {
  const raw = item.json?.analyzed_date;
  if (raw == null || raw === 'null' || raw === '') continue;
  const d = String(raw).slice(0, 10);
  if (d && /^\d{4}-\d{2}-\d{2}$/.test(d)) analyzedDates.push(d);
}

return [{
  json: {
    _impulsarPlanificacion: true,
    analyzedDates,
    analyzedCount: analyzedDates.length,
    sinDiasPrevios: analyzedDates.length === 0
  }
}];

// ── Planificar días pendientes (modo historical) ────────────────────────────
// Devuelve solo el primer día pendiente; el loop continúa desde Guardar resumen día.

function getCfg() {
  const tryNames = [
    'Config histórico', 'config histórico', 'Config Histórico',
    'Configuración', 'configuración', 'Configuracion'
  ];
  for (const name of tryNames) {
    try {
      const j = $(name).first()?.json;
      if (j && (j.mode || j.startDate !== undefined)) return j;
    } catch (e) {}
  }
  throw new Error('Ejecuta Config histórico o Configuración antes de planificar.');
}

function collectAnalyzedSet() {
  const set = new Set();
  const buckets = [];

  buckets.push($input.all());
  try { buckets.push($('Impulsar planificación').all() || []); } catch (e) {}
  try { buckets.push($('Obtener días analizados').all() || []); } catch (e) {}

  for (const items of buckets) {
    for (const item of items) {
      const j = item.json || {};
      if (Array.isArray(j.analyzedDates)) {
        for (const d of j.analyzedDates) {
          const ds = String(d || '').slice(0, 10);
          if (/^\d{4}-\d{2}-\d{2}$/.test(ds)) set.add(ds);
        }
      }
      const d = String(j.analyzed_date || '').slice(0, 10);
      if (/^\d{4}-\d{2}-\d{2}$/.test(d)) set.add(d);
    }
  }
  return set;
}

const cfg = getCfg();
const mode = String(cfg.mode || '').toLowerCase();

if (mode !== 'historical') {
  return [{ json: { _skipHistorical: true, mode } }];
}

const startDate = String(cfg.startDate || '').trim();
const endDate = String(cfg.endDate || '').trim();

if (!startDate || !endDate) {
  throw new Error('Modo historical: indica startDate y endDate (YYYY-MM-DD).');
}

const analyzedSet = collectAnalyzedSet();

function parseYmd(s) {
  const [y, m, d] = s.split('-').map(Number);
  return { y, m, d };
}

function addDays(ymd, n) {
  const dt = new Date(Date.UTC(ymd.y, ymd.m - 1, ymd.d + n, 12, 0, 0));
  return {
    y: dt.getUTCFullYear(),
    m: dt.getUTCMonth() + 1,
    d: dt.getUTCDate()
  };
}

function fmt(ymd) {
  return `${ymd.y}-${String(ymd.m).padStart(2, '0')}-${String(ymd.d).padStart(2, '0')}`;
}

const pending = [];
let cur = parseYmd(startDate);

while (true) {
  const ds = fmt(cur);
  if (ds > endDate) break;
  if (!analyzedSet.has(ds)) pending.push(ds);
  if (ds === endDate) break;
  cur = addDays(cur, 1);
}

if (!pending.length) {
  return [{
    json: {
      _noPendingDays: true,
      rangeStart: startDate,
      rangeEnd: endDate,
      analyzedDaysKnown: analyzedSet.size,
      message: `Todos los días entre ${startDate} y ${endDate} ya están analizados.`
    }
  }];
}

// Un día por ejecución del loop (Guardar resumen día → Obtener días analizados).
const processDate = pending[0];

return [{
  json: {
    processDate,
    rangeStart: startDate,
    rangeEnd: endDate,
    mode: 'historical',
    dayIndex: 1,
    daysPending: pending.length,
    analyzedDaysKnown: analyzedSet.size
  }
}];

// ── Construir consulta Gmail ─────────────────────────────────────────────────
// Modos — leer Config histórico o Configuración (compatible runOnceForEachItem)

function nodeJson(nodeName) {
  try {
    const items = $(nodeName).all();
    if (items && items.length && items[0].json) return items[0].json;
  } catch (e) { /* nodo no ejecutado en esta rama */ }
  return null;
}

function getCfg() {
  for (const name of ['Config histórico', 'Configuración']) {
    const j = nodeJson(name);
    if (j && (j.mode || j.startDate !== undefined)) return j;
  }
  throw new Error('Ejecuta Configuración o Config histórico antes de este nodo.');
}

function inputJson() {
  try {
    const item = $input.item;
    if (item && item.json) return item.json;
  } catch (e) { /* runOnceForAllItems */ }
  const all = $input.all();
  return (all[0] && all[0].json) || {};
}

const cfg = getCfg();
const dayItem = inputJson();
const tzOffset = Number(cfg.tzOffsetHours ?? -5);
const mode = String(dayItem.mode || cfg.mode || 'incremental').toLowerCase();

function startOfDayEpoch(y, monthIndex, d) {
  return Math.floor(Date.UTC(y, monthIndex, d, 0, 0, 0) / 1000) - tzOffset * 3600;
}

function localTodayParts() {
  const localMs = Date.now() + tzOffset * 3600 * 1000;
  const ld = new Date(localMs);
  return { y: ld.getUTCFullYear(), m: ld.getUTCMonth(), d: ld.getUTCDate() };
}

function epochFromYmd(ymd) {
  const [y, m, d] = String(ymd).split('-').map(Number);
  return startOfDayEpoch(y, m - 1, d);
}

let afterEpoch;
let beforeEpoch;
let processDate = null;

if (mode === 'historical') {
  processDate = String(dayItem.processDate || '').trim();
  if (!processDate) {
    throw new Error('Modo historical: falta processDate (Planificar días pendientes).');
  }
  afterEpoch = epochFromYmd(processDate);
  beforeEpoch = afterEpoch + 86400;
} else if (mode === 'range') {
  if (!cfg.startDate || !cfg.endDate) {
    throw new Error('Modo "range": indica startDate y endDate (YYYY-MM-DD) en Configuración.');
  }
  afterEpoch = epochFromYmd(cfg.startDate);
  beforeEpoch = epochFromYmd(cfg.endDate) + 86400;
} else if (mode === 'today') {
  const { y, m, d } = localTodayParts();
  afterEpoch = startOfDayEpoch(y, m, d);
  beforeEpoch = afterEpoch + 86400;
} else {
  beforeEpoch = Math.floor(Date.now() / 1000);
  const { y, m, d } = localTodayParts();
  afterEpoch = startOfDayEpoch(y, m, d);

  const last = nodeJson('Obtener última revisión') || {};
  const lastEpoch = Number(last.last_search_before_epoch || 0);
  if (lastEpoch > 0) {
    const lastLocalMs = lastEpoch * 1000 + tzOffset * 3600 * 1000;
    const ld = new Date(lastLocalMs);
    const sameDay =
      ld.getUTCFullYear() === y &&
      ld.getUTCMonth() === m &&
      ld.getUTCDate() === d;
    if (sameDay && lastEpoch < beforeEpoch) {
      afterEpoch = lastEpoch;
    }
  }
}

let q = `after:${afterEpoch} before:${beforeEpoch}`;

if (cfg.receivedOnly !== false) {
  const mailbox = String(cfg.monitorMailbox || 'telemetria@zgroup.com.pe').trim();
  q += ' -in:sent';
  if (mailbox) q += ` -from:${mailbox}`;
}

// En historical: NO filtrar en Gmail — se listan todos los recibidos del día
if (cfg.keywordFilterEnabled !== false && mode !== 'historical') {
  const telemetriaKws = Array.isArray(cfg.telemetriaVariants) && cfg.telemetriaVariants.length
    ? cfg.telemetriaVariants
    : ['telemetria', 'telemtria', 'telemetrai', 'ztrack', 'api', 'software', 'plataforma'];
  const persons = Array.isArray(cfg.keywords) && cfg.keywords.length
    ? cfg.keywords
    : ['Luis', 'Eusebio'];
  const telPart = telemetriaKws.map(k => `"${String(k).trim()}"`).filter(Boolean).join(' OR ');
  const personPart = persons.map(k => `"${String(k).trim()}"`).filter(Boolean).join(' OR ');
  if (telPart && personPart) q += ` (${telPart}) (${personPart})`;
}

let knownIdsQuery;
if (mode === 'historical') {
  const d = processDate.replace(/'/g, '');
  knownIdsQuery = `SELECT message_id FROM email_trace WHERE trace_status = 'active' AND review_mode = 'historical' AND search_after::date = '${d}'::date`;
} else if (mode === 'range') {
  const start = String(cfg.startDate).trim();
  const end = String(cfg.endDate).trim();
  knownIdsQuery = `SELECT message_id FROM email_trace WHERE trace_status = 'active' AND review_mode = 'range' AND email_date >= '${start}'::date AND email_date < ('${end}'::date + INTERVAL '1 day')`;
} else {
  knownIdsQuery = `SELECT message_id FROM email_trace WHERE trace_status = 'active' AND review_mode = 'incremental' AND search_before::date = CURRENT_DATE`;
}

return [{
  json: {
    gmailQuery: q,
    reviewMode: mode,
    processDate,
    knownIdsQuery,
    afterEpoch,
    beforeEpoch,
    afterIso: new Date(afterEpoch * 1000).toISOString(),
    beforeIso: new Date(beforeEpoch * 1000).toISOString(),
    searchWindow: `${new Date(afterEpoch * 1000).toISOString()} → ${new Date(beforeEpoch * 1000).toISOString()}`,
    rangeStart: mode === 'historical' ? (dayItem.rangeStart || cfg.startDate) : (mode === 'range' ? String(cfg.startDate) : null),
    rangeEnd: mode === 'historical' ? (dayItem.rangeEnd || cfg.endDate) : (mode === 'range' ? String(cfg.endDate) : null)
  }
}];

// ── Filtrar solo correos no registrados en email_trace ─────────────────────
// Entrada: respuesta de Gmail messages.list → { messages: [{ id, threadId }] }
//
// Requiere que en el MISMO run hayan ejecutado antes:
//   Construir consulta Gmail → Listar IDs Gmail → (este nodo)
//   Construir consulta Gmail → Obtener IDs en BD (rama paralela, puede 0 filas)
//
// Si Configuración.skipKnownInDb = false, deja pasar todos.

function safeAll(nodeName) {
  try {
    return $(nodeName).all() || [];
  } catch (e) {
    return [];
  }
}

function safeFirstJson(nodeName) {
  try {
    return $(nodeName).first()?.json || null;
  } catch (e) {
    return null;
  }
}

function getCfg() {
  for (const name of ['Config histórico', 'Configuración']) {
    try {
      const j = $(name).first()?.json;
      if (j && (j.mode || j.startDate !== undefined)) return j;
    } catch (e) {}
  }
  throw new Error('Ejecuta Configuración o Config histórico.');
}

const cfg = getCfg();
const skipKnown = cfg.skipKnownInDb !== false;

function qinfoForDay() {
  try {
    const j = $('Construir consulta Gmail').item?.json;
    if (j && j.gmailQuery) return j;
  } catch (e) { /* optional */ }
  return safeFirstJson('Construir consulta Gmail');
}

const qinfo = qinfoForDay();
if (!qinfo || !qinfo.gmailQuery) {
  throw new Error(
    'Falta ejecutar "Construir consulta Gmail" antes de "Filtrar solo nuevos".'
  );
}

function knownIdsForCurrentDay() {
  const ids = new Set();
  try {
    const paired = $('Obtener IDs en BD').item;
    if (paired && paired.json && paired.json.message_id) {
      ids.add(paired.json.message_id);
      return ids;
    }
  } catch (e) { /* optional */ }
  for (const item of safeAll('Obtener IDs en BD')) {
    const id = item.json && item.json.message_id;
    if (id) ids.add(id);
  }
  return ids;
}

const known = knownIdsForCurrentDay();

const listResp = $input.first().json;
const messages = Array.isArray(listResp.messages) ? listResp.messages : [];

if (!messages.length) {
  return [{
    json: {
      _empty: true,
      reason: 'sin_correos_en_gmail',
      totalListed: 0,
      totalNew: 0,
      _qinfo: qinfo,
      _dayCtx: {
        processDate: qinfo.processDate,
        rangeStart: qinfo.rangeStart,
        rangeEnd: qinfo.rangeEnd
      }
    }
  }];
}

const nuevos = messages.filter(m => m && m.id && (!skipKnown || !known.has(m.id)));

if (!nuevos.length) {
  return [{
    json: {
      _empty: true,
      reason: 'todos_ya_en_bd',
      totalListed: messages.length,
      totalKnown: known.size,
      totalNew: 0,
      gmailQuery: qinfo.gmailQuery,
      _qinfo: qinfo,
      _dayCtx: {
        processDate: qinfo.processDate,
        rangeStart: qinfo.rangeStart,
        rangeEnd: qinfo.rangeEnd
      }
    }
  }];
}

return nuevos.map(m => ({
  json: {
    id: m.id,
    threadId: m.threadId,
    gmailQuery: qinfo.gmailQuery,
    reviewMode: qinfo.reviewMode,
    _qinfo: qinfo,
    _dayCtx: {
      processDate: qinfo.processDate,
      rangeStart: qinfo.rangeStart,
      rangeEnd: qinfo.rangeEnd
    },
    _meta: {
      totalListed: messages.length,
      totalKnown: known.size,
      totalNew: nuevos.length
    }
  }
}));

// ── Cortar rama si no hay correos nuevos que procesar ───────────────────────
// Evita llamar a Gmail Get / Normalizar cuando Filtrar solo nuevos devolvió
// un marcador _empty.

const out = [];
for (const item of $input.all()) {
  if (item.json && item.json._empty) continue;
  if (!item.json || !item.json.id) continue;
  out.push(item);
}
return out;

// ── Normalizar correo (SOLO texto + REFERENCIAS de adjuntos) ────────────────
// Entrada típica del nodo Gmail v2 con **Simplify = OFF** (simple: false):
//   parseRawEmail → from/to/cc/subject/date/text/html + headers (objeto)
// Entrada alternativa con **Simplify = ON** (simple: true):
//   simplifyOutput → payload.parts + campos planos From/To/Subject
//
// Produce, por cada correo, un item con:
//   • claves = columnas de email_trace (solo texto)
//   • attachments[] = referencias de adjuntos (sin binarios) para el siguiente nodo
//
// Adjuntos: si Gmail tiene "Download Attachments = ON", lee metadatos de $binary
// (filename, mimeType, size) sin persistir el binario. Si no hay binary, recorre
// payload.parts cuando exista (formato API).

const qinfoById = new Map();
try {
  for (const item of $('Filtrar solo nuevos').all()) {
    const j = item.json || {};
    if (j.id && j._qinfo) qinfoById.set(j.id, j._qinfo);
  }
} catch (e) { /* optional */ }

function qinfoForMessage(messageId) {
  if (messageId && qinfoById.has(messageId)) return qinfoById.get(messageId);
  try { return $('Construir consulta Gmail').first().json; } catch (e) { return {}; }
}

function headerVal(m, name) {
  const payload = m.payload || {};
  if (Array.isArray(payload.headers)) {
    const h = payload.headers.find(x => (x.name || '').toLowerCase() === name.toLowerCase());
    if (h && h.value) return h.value;
  }
  const flat = m[name] || m[name.charAt(0).toUpperCase() + name.slice(1).toLowerCase()];
  if (typeof flat === 'string' && flat.trim()) return flat;

  const hdrs = m.headers;
  if (hdrs && typeof hdrs === 'object' && !Array.isArray(hdrs)) {
    const key = name.toLowerCase();
    const line = hdrs[key];
    if (typeof line === 'string' && line.trim()) {
      const idx = line.indexOf(':');
      return idx >= 0 ? line.slice(idx + 1).trim() : line.trim();
    }
  }
  return '';
}

function addressText(field) {
  if (!field) return '';
  if (typeof field === 'string') return field.trim();
  if (typeof field.text === 'string' && field.text.trim()) return field.text.trim();
  if (Array.isArray(field.value)) {
    return field.value
      .map(v => {
        const addr = (v && v.address) || '';
        const nm = (v && v.name) || '';
        if (nm && addr) return `"${nm}" <${addr}>`;
        return addr || nm;
      })
      .filter(Boolean)
      .join(', ');
  }
  return '';
}

function decodeB64Url(data) {
  if (!data) return '';
  const b64 = data.replace(/-/g, '+').replace(/_/g, '/');
  try { return Buffer.from(b64, 'base64').toString('utf-8'); } catch (e) { return ''; }
}

function stripHtml(html) {
  return html
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<img[\s\S]*?>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanBodyText(text) {
  return String(text || '')
    .replace(/\[image:[^\]]*\]/gi, ' ')
    .replace(/\[cid:[^\]]*\]/gi, ' ')
    .replace(/<\s*mailto:[^>]+>/gi, ' ')
    .replace(/\bimage\d{3}\.(png|jpe?g|gif|webp)\b/gi, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\s+/g, ' ')
    .trim();
}

function isPdfAttachment(filename, mime) {
  const fn = String(filename || '').toLowerCase();
  const mt = String(mime || '').toLowerCase();
  return fn.endsWith('.pdf') || mt === 'application/pdf' || mt.includes('pdf');
}

function parseEmailDate(m) {
  const candidates = [m.date, m.internalDate, headerVal(m, 'Date')];
  for (const raw of candidates) {
    if (raw == null || raw === '') continue;
    const d = typeof raw === 'number' || /^\d+$/.test(String(raw))
      ? new Date(Number(raw))
      : new Date(raw);
    if (!isNaN(d.getTime())) return d.toISOString();
  }
  return null;
}

function attachmentsFromParts(payload) {
  const attachments = [];
  function walk(part) {
    if (!part) return;
    const mime = part.mimeType || '';
    const filename = part.filename || '';
    if (filename && isPdfAttachment(filename, mime)) {
      attachments.push({
        filename,
        mime_type: mime,
        size_bytes: (part.body && part.body.size) || 0,
        attachment_id: (part.body && part.body.attachmentId) || ''
      });
    } else if (mime === 'text/plain' && part.body && part.body.data) {
      // body parts — no attachment
    } else if (mime === 'text/html' && part.body && part.body.data) {
      // body parts — no attachment
    }
    if (Array.isArray(part.parts)) part.parts.forEach(walk);
  }
  walk(payload);
  return attachments;
}

function attachmentsFromBinary(binary) {
  if (!binary || typeof binary !== 'object') return [];
  const attachments = [];
  for (const [key, meta] of Object.entries(binary)) {
    if (!meta || typeof meta !== 'object') continue;
    const filename = meta.fileName || meta.filename || key;
    const mime = meta.mimeType || meta.mime_type || '';
    if (!isPdfAttachment(filename, mime)) continue;
    let sizeBytes = 0;
    if (typeof meta.fileSize === 'string') {
      const n = parseFloat(meta.fileSize.split(/\s+/)[0]);
      if (!isNaN(n)) {
        const unit = (meta.fileSize.split(/\s+/)[1] || '').toUpperCase();
        sizeBytes = unit.startsWith('M') ? Math.round(n * 1024 * 1024)
          : unit.startsWith('G') ? Math.round(n * 1024 * 1024 * 1024)
          : unit.startsWith('K') ? Math.round(n * 1024)
          : Math.round(n);
      }
    }
    attachments.push({
      filename,
      mime_type: meta.mimeType || meta.mime_type || '',
      size_bytes: sizeBytes,
      attachment_id: ''
    });
  }
  return attachments;
}

function bodyTextFromMessage(m) {
  if (typeof m.text === 'string' && m.text.trim()) return m.text.trim();
  if (typeof m.html === 'string' && m.html.trim()) return stripHtml(m.html);

  const payload = m.payload || {};
  let textPlain = '';
  let textHtml = '';
  function walk(part) {
    if (!part) return;
    const mime = part.mimeType || '';
    if (mime === 'text/plain' && part.body && part.body.data) {
      textPlain += decodeB64Url(part.body.data);
    } else if (mime === 'text/html' && part.body && part.body.data) {
      textHtml += decodeB64Url(part.body.data);
    }
    if (Array.isArray(part.parts)) part.parts.forEach(walk);
  }
  walk(payload);
  if (textPlain.trim()) return textPlain.trim();
  if (textHtml.trim()) return stripHtml(textHtml);
  if (typeof m.snippet === 'string' && m.snippet.trim()) return m.snippet.trim();
  return '';
}

const out = [];

for (const item of $input.all()) {
  const m = item.json;
  const qinfo = qinfoForMessage(m.id);
  const payload = m.payload || {};

  let attachments = attachmentsFromParts(payload);
  if (!attachments.length) attachments = attachmentsFromBinary(item.binary);

  let bodyText = cleanBodyText(bodyTextFromMessage(m));
  const snippet = (typeof m.snippet === 'string' && m.snippet.trim())
    ? m.snippet.trim()
    : bodyText.slice(0, 200);

  const messageId = m.id;
  const gmailLink = `https://mail.google.com/mail/u/0/#all/${messageId}`;

  out.push({
    json: {
      message_id:      messageId,
      thread_id:       m.threadId,
      from_address:    addressText(m.from) || headerVal(m, 'From'),
      to_addresses:    addressText(m.to) || headerVal(m, 'To'),
      cc_addresses:    addressText(m.cc) || headerVal(m, 'Cc'),
      subject:         (typeof m.subject === 'string' ? m.subject : '') || headerVal(m, 'Subject'),
      email_date:      parseEmailDate(m),
      body_text:       bodyText,
      snippet,
      has_attachments: attachments.length > 0,
      gmail_link:      gmailLink,
      search_query:    qinfo.gmailQuery,
      search_after:    qinfo.afterIso,
      search_before:   qinfo.beforeIso,
      review_mode:     qinfo.reviewMode,
      label_ids:       Array.isArray(m.labelIds) ? m.labelIds : [],
      attachments
    }
  });
}

return out;

// ── Filtrar: recibidos + keyword telemetría AND (Luis OR Eusebio) ───────────
// Reglas:
//   • Palabra suelta (límite \b): telemetria, ztrack, api, software, plataforma…
//   • NO cuenta dentro de correos: telemetria@…, @telemetria@…
//   • NO cuenta en encabezados CC/Para: 'ZTRACK TELEMETRY' <ztrack@…>,
//     'telemetria zgroup' <telemetria@…>, listas con ; y <...@…>
//   • Luis / Eusebio: palabra suelta, fuera de correos y encabezados
//   • Dos fragmentos independientes (telemetría + persona)

function getCfg() {
  for (const name of ['Config histórico', 'Configuración']) {
    try {
      const j = $(name).first()?.json;
      if (j && (j.mode || j.startDate !== undefined)) return j;
    } catch (e) {}
  }
  throw new Error('Ejecuta Configuración o Config histórico.');
}

const cfg = getCfg();
const monitor = String(cfg.monitorMailbox || 'telemetria@zgroup.com.pe').toLowerCase();
const receivedOnly = cfg.receivedOnly !== false;
const keywordEnabled = cfg.keywordFilterEnabled !== false;
const excerptRadius = Number(cfg.matchExcerptRadius ?? 120);
const personKws = (Array.isArray(cfg.keywords) && cfg.keywords.length)
  ? cfg.keywords
  : ['Luis', 'Eusebio'];

const telemetriaVariants = Array.isArray(cfg.telemetriaVariants) && cfg.telemetriaVariants.length
  ? cfg.telemetriaVariants
  : ['telemetria', 'telemtria', 'telemetrai', 'ztrack', 'api', 'software', 'plataforma'];

const HEADER_LABEL_BLOCKLIST = [
  /ztrack\s+telemetry/i,
  /telemetria\s+zgroup/i,
];

function escapeRe(s) {
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function excerptAround(text, pos, radius) {
  if (text == null || pos == null || pos < 0) return '';
  const s = String(text);
  const start = Math.max(0, pos - radius);
  const end = Math.min(s.length, pos + radius);
  let chunk = s.slice(start, end).replace(/\s+/g, ' ').trim();
  if (start > 0) chunk = '…' + chunk;
  if (end < s.length) chunk = chunk + '…';
  return chunk;
}

function fieldAtPosition(subject, body, snippet, pos) {
  const sub = String(subject || '');
  const bod = String(body || '');
  const subEnd = sub.length;
  const bodyEnd = subEnd + 1 + bod.length;
  if (pos < subEnd) return 'subject';
  if (pos < bodyEnd) return 'body';
  return 'snippet';
}

function buildHaystack(subject, body, snippet) {
  return `${subject || ''}\n${body || ''}\n${snippet || ''}`;
}

function isInsideAngleEmail(text, start, end) {
  const lt = text.lastIndexOf('<', start);
  if (lt < 0 || lt < start - 120) return false;
  const gt = text.indexOf('>', end);
  if (gt < 0 || gt > end + 120) return false;
  const inner = text.slice(lt + 1, gt);
  return inner.includes('@');
}

function isInsideEmail(text, start, end) {
  const charBefore = start > 0 ? text[start - 1] : '';
  const charAfter = end < text.length ? text[end] : '';

  if (charBefore === '@' || charAfter === '@') return true;
  if (isInsideAngleEmail(text, start, end)) return true;

  let left = start;
  while (left > 0 && /[\w.+-]/.test(text[left - 1])) left--;
  if (left > 0 && text[left - 1] === '@') {
    left--;
    while (left > 0 && /[\w.+-]/.test(text[left - 1])) left--;
  }

  let right = end;
  while (right < text.length && /[\w.+-]/.test(text[right])) right++;
  if (right < text.length && text[right] === '@') {
    right++;
    while (right < text.length && /[\w.+-]/.test(text[right])) right++;
  }

  const token = text.slice(left, right);
  if (!token.includes('@')) return false;

  if (/^@[\w.+-]+@[\w.-]+\.[\w.-]+/.test(token)) return true;
  if (/^[\w.+-]+@[\w.-]+\.[\w.-]+/.test(token)) return true;

  return false;
}

/** 'Nombre visible' <correo@dominio> — encabezado Para/CC, no referencia real */
function isInsideQuotedDisplayName(text, start, end) {
  const scanStart = Math.max(0, start - 140);
  const scanEnd = Math.min(text.length, end + 100);
  const chunk = text.slice(scanStart, scanEnd);
  const re = /(['"])([^'"]*)\1\s*<[^>]*@[^>]+>/g;
  let m;
  while ((m = re.exec(chunk)) !== null) {
    const nameStart = scanStart + m.index + m[1].length;
    const nameEnd = nameStart + m[2].length;
    if (start >= nameStart && end <= nameEnd) return true;
  }
  return false;
}

/** Etiquetas conocidas de buzón en encabezados (ZTRACK TELEMETRY, telemetria zgroup) */
function isKnownHeaderLabel(text, start, end) {
  const winStart = Math.max(0, start - 30);
  const winEnd = Math.min(text.length, end + 50);
  const window = text.slice(winStart, winEnd);
  for (const pat of HEADER_LABEL_BLOCKLIST) {
    const m = pat.exec(window);
    if (!m) continue;
    const absStart = winStart + m.index;
    const absEnd = absStart + m[0].length;
    if (start >= absStart && end <= absEnd) return true;
  }
  return false;
}

/** Bloque tipo lista de destinatarios: varios @ y <…>; en la misma ventana */
function isInRecipientListBlock(text, start, end) {
  const winStart = Math.max(0, start - 180);
  const winEnd = Math.min(text.length, end + 180);
  const window = text.slice(winStart, winEnd);

  const hasAngleEmail = /<[^>]*@[^>]+>/.test(window);
  const hasBareEmail = /[\w.+-]+@[\w.-]+\.\w+/.test(window);
  if (!hasAngleEmail && !hasBareEmail) return false;

  const atCount = (window.match(/@/g) || []).length;
  const semiCount = (window.match(/;/g) || []).length;
  const gtSemi = (window.match(/>\s*;/g) || []).length;

  if (atCount >= 2 && (semiCount >= 1 || gtSemi >= 1)) {
    if (isInsideQuotedDisplayName(text, start, end)) return true;
    if (isKnownHeaderLabel(text, start, end)) return true;
    if (isInsideEmail(text, start, end)) return true;
    if (hasAngleEmail && (semiCount >= 1 || window.includes("'") || window.includes('"'))) {
      return true;
    }
  }
  return false;
}

function isInvalidMatchContext(text, start, end) {
  return isInsideEmail(text, start, end)
    || isInsideQuotedDisplayName(text, start, end)
    || isKnownHeaderLabel(text, start, end)
    || isInRecipientListBlock(text, start, end);
}

function isSentByMonitor(fromAddress, labelIds) {
  const from = String(fromAddress || '').toLowerCase();
  if (from.includes(monitor)) return true;
  if (Array.isArray(labelIds) && labelIds.includes('SENT')) return true;
  return false;
}

function findStandaloneKeyword(haystack, keywords) {
  const candidates = [];

  for (const kw of keywords) {
    const re = new RegExp(`\\b${escapeRe(kw)}\\b`, 'gi');
    let m;
    while ((m = re.exec(haystack)) !== null) {
      const start = m.index;
      const end = start + m[0].length;
      if (isInvalidMatchContext(haystack, start, end)) continue;
      candidates.push({
        position: start,
        matched: m[0],
        keyword: kw
      });
    }
  }

  if (!candidates.length) return null;
  candidates.sort((a, b) => a.position - b.position);
  return candidates[0];
}

const out = [];

for (const item of $input.all()) {
  const m = item.json;

  if (receivedOnly && isSentByMonitor(m.from_address, m.label_ids)) {
    continue;
  }

  if (keywordEnabled) {
    const haystack = buildHaystack(m.subject, m.body_text, m.snippet);
    const tel = findStandaloneKeyword(haystack, telemetriaVariants);
    if (!tel) continue;
    const person = findStandaloneKeyword(haystack, personKws);
    if (!person) continue;

    m.match_telemetria_pos = tel.position;
    m.match_telemetria_keyword = tel.matched;
    m.match_telemetria_excerpt = excerptAround(haystack, tel.position, excerptRadius);
    m.match_person_pos = person.position;
    m.match_person_keyword = person.matched;
    m.match_person_excerpt = excerptAround(haystack, person.position, excerptRadius);
    m.match_in_field = fieldAtPosition(m.subject, m.body_text, m.snippet, tel.position);
  }

  out.push({ json: m });
}

const mode = String(cfg.mode || '').toLowerCase();
const inputCount = $input.all().length;

// Histórico: correos leídos pero ningún match → cerrar día igual (cierra loop Split)
if (!out.length && mode === 'historical' && inputCount > 0) {
  return [{
    json: {
      _cerrarDiaHistorico: true,
      emailsProcessed: inputCount
    }
  }];
}

return out;

// ── Preparar insert email_trace (sin campos auxiliares) ─────────────────────
const out = [];
for (const item of $input.all()) {
  const { attachments, label_ids, ...row } = item.json;
  out.push({
    json: {
      ...row,
      trace_status: row.trace_status || 'active'
    }
  });
}
return out;

// ── Expandir adjuntos (una fila por referencia de adjunto) ──────────────────
// Toma la salida del normalizador y emite un item por cada adjunto, con las
// claves = columnas de email_attachment_ref. Si el correo no tiene adjuntos,
// no emite nada para ese correo.

const out = [];

for (const item of $input.all()) {
  const m = item.json;
  const atts = Array.isArray(m.attachments) ? m.attachments : [];
  for (const a of atts) {
    out.push({
      json: {
        message_id:    m.message_id,
        thread_id:     m.thread_id,
        filename:      a.filename || '',
        mime_type:     a.mime_type || '',
        size_bytes:    a.size_bytes || 0,
        attachment_id: a.attachment_id || '',
        gmail_link:    m.gmail_link
      }
    });
  }
}

return out;

// ── Registrar resumen del día histórico ─────────────────────────────────────
// Consolida IDs y genera SQL upsert seguro para email_history_day.

function safeAll(nodeName) {
  try { return $(nodeName).all() || []; } catch (e) { return []; }
}

function safeFirstJson(nodeName) {
  try { return $(nodeName).first()?.json || null; } catch (e) { return null; }
}

function pgStr(v) {
  return `'${String(v ?? '').replace(/'/g, "''")}'`;
}

function pgJson(arr) {
  return `'${JSON.stringify(arr || [])}'::jsonb`;
}

function getCfg() {
  for (const name of ['Config histórico', 'Configuración']) {
    try {
      const j = $(name).first()?.json;
      if (j && (j.mode || j.startDate !== undefined)) return j;
    } catch (e) {}
  }
  throw new Error('Ejecuta Configuración o Config histórico.');
}

const cfg = getCfg();
const qinfoMain = safeFirstJson('Construir consulta Gmail') || {};
const filtrarRow = safeFirstJson('Filtrar solo nuevos') || {};
const dayCtx =
  filtrarRow._dayCtx ||
  $input.first()?.json?._dayCtx ||
  {
    processDate: qinfoMain.processDate,
    rangeStart: qinfoMain.rangeStart || cfg.startDate,
    rangeEnd: qinfoMain.rangeEnd || cfg.endDate
  };

const processDate = dayCtx.processDate || qinfoMain.processDate;
if (!processDate) {
  throw new Error('Registrar día histórico: falta processDate del día en curso.');
}

const listRespMain = safeFirstJson('Listar IDs Gmail') || {};
const qinfo =
  (() => {
    try {
      const j = $('Construir consulta Gmail').item?.json;
      if (j && j.gmailQuery) return j;
    } catch (e) { /* optional */ }
    return qinfoMain;
  })();
const listResp =
  (() => {
    try {
      return $('Listar IDs Gmail').item?.json || listRespMain;
    } catch (e) {
      return listRespMain;
    }
  })();

const listedIds = Array.isArray(listResp.messages)
  ? listResp.messages.map(m => m && m.id).filter(Boolean)
  : [];

const processedIds = safeAll('Normalizar correo')
  .map(i => i.json.message_id)
  .filter(Boolean);

const matchIds = safeAll('Filtrar recibidos relevantes')
  .map(i => i.json.message_id)
  .filter(Boolean);

const inputJson = $input.first()?.json || {};
const emptyDay = inputJson._empty === true || inputJson._historicalEmptyDay === true;

const row = {
  analyzed_date: processDate,
  range_start: dayCtx.rangeStart || cfg.startDate,
  range_end: dayCtx.rangeEnd || cfg.endDate,
  gmail_query: qinfo.gmailQuery || '',
  emails_listed_count: listedIds.length,
  emails_processed_count: emptyDay ? 0 : processedIds.length,
  emails_match_count: matchIds.length,
  message_ids_listed: listedIds,
  message_ids_processed: emptyDay ? [] : processedIds,
  message_ids_match: matchIds,
  status: 'completed',
  empty_day: emptyDay
};

const upsertSql = `
INSERT INTO email_history_day (
  analyzed_date, range_start, range_end, gmail_query,
  emails_listed_count, emails_processed_count, emails_match_count,
  message_ids_listed, message_ids_processed, message_ids_match,
  status, analyzed_at
) VALUES (
  ${pgStr(row.analyzed_date)}::date,
  ${pgStr(row.range_start)}::date,
  ${pgStr(row.range_end)}::date,
  ${pgStr(row.gmail_query)},
  ${row.emails_listed_count},
  ${row.emails_processed_count},
  ${row.emails_match_count},
  ${pgJson(row.message_ids_listed)},
  ${pgJson(row.message_ids_processed)},
  ${pgJson(row.message_ids_match)},
  ${pgStr(row.status)},
  now()
)
ON CONFLICT (analyzed_date) DO UPDATE SET
  range_start = EXCLUDED.range_start,
  range_end = EXCLUDED.range_end,
  gmail_query = EXCLUDED.gmail_query,
  emails_listed_count = EXCLUDED.emails_listed_count,
  emails_processed_count = EXCLUDED.emails_processed_count,
  emails_match_count = EXCLUDED.emails_match_count,
  message_ids_listed = EXCLUDED.message_ids_listed,
  message_ids_processed = EXCLUDED.message_ids_processed,
  message_ids_match = EXCLUDED.message_ids_match,
  status = EXCLUDED.status,
  analyzed_at = now()
RETURNING analyzed_date::text AS analyzed_date,
  emails_listed_count, emails_processed_count, emails_match_count;
`.trim();

return [{ json: { ...row, upsertSql } }];

// ── Validar contraseña de reinicio ──────────────────────────────────────────
// Entrada: nodo "Config reinicio" con resetPassword.
// Contraseña esperada: ZTRACKPERU2026

const RESET_PASSWORD = 'ZTRACKPERU2026';
const pwd = String($input.first().json.resetPassword || '').trim();

if (pwd !== RESET_PASSWORD) {
  throw new Error(
    'Contraseña de reinicio incorrecta. Operación cancelada. ' +
    'Indica ZTRACKPERU2026 en el nodo "Config reinicio" antes de ejecutar.'
  );
}

return [{
  json: {
    resetOk: true,
    resetAt: new Date().toISOString(),
    message:
      'Contraseña válida. Se marcarán como superseded los correos activos ' +
      'y se reprocesará el día de hoy desde el inicio.'
  }
}];
